import{_ as n,Z as a,P as s,g as r,k as l,m as i}from"./chunks/framework.Dp5g00Bf.js";const v=JSON.parse('{"title":"ios侧载应用自由","description":"","frontmatter":{},"headers":[],"relativePath":"views/2-软件📲/系统操作/ios侧载应用自由/index.md","filePath":"views/2-软件📲/系统操作/ios侧载应用自由/index.md","lastUpdated":1778336291000}'),d={name:"views/2-软件📲/系统操作/ios侧载应用自由/index.md"};function p(c,e,h,m,g,_){const t=a("NolebaseGitContributors"),o=a("NolebaseGitChangelog");return s(),r("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1778336291000"},[e[0]||(e[0]=l('<h1 id="ios侧载应用自由" tabindex="-1">ios侧载应用自由 <a class="header-anchor" href="#ios侧载应用自由" aria-label="Permalink to &quot;ios侧载应用自由&quot;">​</a></h1><p>ios除了在少数地区开启了侧载，允许用户从第三方应用商店下载ios应用，其他地方基本只能从官方下载。很多时候我们需要测试或者使用一些第三方的ipa应用时，繁琐并且限制很多，比如免费的开发者账号同一设备最多只能安装三个测试应用，并且有效期只有7天。如果想要一年有效期与更多应用并且能够上架应用商店则需要每年缴纳99美元的苹果税。本教程将会教你突破应用安装数量限制与自动续签。</p><h2 id="前期准备" tabindex="-1">前期准备 <a class="header-anchor" href="#前期准备" aria-label="Permalink to &quot;前期准备&quot;">​</a></h2><ul><li>一台iPhone或者iPad(系统ios17以及以上，但是不得高于ios26.3)</li><li>一台装有iTunes的windows电脑或者开箱即用的mac</li><li>altstore pc端 安装包(用于续签)</li><li>livecontainer ipa安装包(用于安装多个应用，它有点类似docker容器)</li></ul><h2 id="altstore安装" tabindex="-1">AltStore安装 <a class="header-anchor" href="#altstore安装" aria-label="Permalink to &quot;AltStore安装&quot;">​</a></h2><p>首先安装AltStore的pc端，它相当于一个服务端，可以直接帮我们安装AltStore的移动端。在上面点击下载，之后输入我们的苹果账号和密码，少做片刻我们的手机上就会安装好它的移动端。</p><p><img src="https://cdn.jsdelivr.net/gh/Ruin-L/image/img/20260301110427980.avif" alt=""></p><p>安装完毕后，我们是无法打开的，还需要在设置的隐私与安全性里开启ios的开发者模式，并重启。 <img src="https://cdn.jsdelivr.net/gh/Ruin-L/image/img/20260301110856933.avif" alt=""></p><p>重启完成后，在vpn的设备管理里点击验证。</p><p><img src="https://cdn.jsdelivr.net/gh/Ruin-L/image/img/20260301111112555.avif" alt="img">至此AltStore已成功安装。</p><h2 id="livecontainer安装" tabindex="-1">livecontainer安装 <a class="header-anchor" href="#livecontainer安装" aria-label="Permalink to &quot;livecontainer安装&quot;">​</a></h2><p>手机端进入后，打开myappstab页面，点击左上角的加号，会进入文件管理页面，点击对应的ipa文件进行安装即可。</p><p><img src="https://cdn.jsdelivr.net/gh/Ruin-L/image/img/20260301111459613.avif" alt=""></p>',13)),i(t),i(o)])}const f=n(d,[["render",p]]);export{v as __pageData,f as default};
